// Ch4 continued: Communicating Test Status in Agile (1251–1350)
const ch4 = [
{id:1251,chapter:"Communicating Test Status in Agile",topic:"Test Metrics in Agile",difficulty:"easy",question:"Which metric is MOST useful for tracking defect resolution progress in Agile?",options:["A. Lines of code written","B. Open vs closed defect count over time","C. Number of user stories planned","D. Sprint velocity"],answer:1,explanation:"Tracking open vs closed defects over time shows whether the team is resolving issues faster than they are being found."},
{id:1252,chapter:"Communicating Test Status in Agile",topic:"Test Metrics in Agile",difficulty:"medium",question:"What does code coverage measure?",options:["A. The number of test cases written","B. The percentage of production code exercised by automated tests","C. The number of features delivered","D. The percentage of stories accepted by the PO"],answer:1,explanation:"Code coverage measures what percentage of the codebase is executed when the automated test suite runs."},
{id:1253,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"easy",question:"In Scrum, velocity is BEST described as:",options:["A. The speed at which developers type code","B. The average amount of work a team completes per sprint","C. The number of defects found per sprint","D. The deployment frequency"],answer:1,explanation:"Velocity is the average story points (or units of work) completed per sprint, used for forecasting."},
{id:1254,chapter:"Communicating Test Status in Agile",topic:"Test Reporting",difficulty:"medium",question:"A lightweight test summary report in Agile should include:",options:["A. A full list of all test cases with their steps","B. Test objectives, scope, results, risks, and recommendations","C. Only the number of tests passed","D. The project budget"],answer:1,explanation:"Even a lightweight Agile test report should cover objectives, scope, results, outstanding risks, and next steps."},
{id:1255,chapter:"Communicating Test Status in Agile",topic:"Retrospective",difficulty:"easy",question:"When is a retrospective held in Scrum?",options:["A. Before every sprint","B. At the end of each sprint","C. Only at project completion","D. During the sprint review"],answer:1,explanation:"The Sprint Retrospective is held at the end of each sprint to inspect and improve the team's process."},
{id:1256,chapter:"Communicating Test Status in Agile",topic:"Retrospective",difficulty:"medium",question:"What is the PRIMARY purpose of a sprint retrospective from a testing perspective?",options:["A. To accept or reject user stories","B. To identify testing process improvements for the next sprint","C. To plan the next sprint backlog","D. To demo the product to stakeholders"],answer:1,explanation:"The retrospective allows the team — including testers — to reflect on what worked, what didn't, and improve testing practices."},
{id:1257,chapter:"Communicating Test Status in Agile",topic:"Test Dashboard",difficulty:"medium",question:"An information radiator in Agile is:",options:["A. A formal monthly status report","B. A large visible display showing current team metrics and progress","C. An automated performance testing tool","D. A backlog management system"],answer:1,explanation:"Information radiators are highly visible displays (physical or digital) that broadcast real-time team status to everyone."},
{id:1258,chapter:"Communicating Test Status in Agile",topic:"Test Dashboard",difficulty:"hard",question:"Which of the following BEST describes a risk-based test status report?",options:["A. A report listing only passed tests","B. A report that highlights which risks remain uncovered by testing","C. A report showing team velocity","D. A report of the number of automated tests"],answer:1,explanation:"Risk-based status reports communicate which product risks are still not adequately tested, enabling prioritised decision-making."},
{id:1259,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"easy",question:"Who should have access to the test status in an Agile team?",options:["A. Only the test lead","B. The whole team including the Product Owner","C. Only management","D. Only developers"],answer:1,explanation:"Transparency is a Scrum pillar — test status should be visible to the whole team, including the Product Owner."},
{id:1260,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"medium",question:"A tester notices testing is falling behind mid-sprint. The BEST immediate action is:",options:["A. Work overtime quietly","B. Raise the issue at the Daily Scrum and ask for help","C. Reduce the number of test cases","D. Wait for the sprint review to report it"],answer:1,explanation:"The Daily Scrum is the right place to surface impediments so the team can swarm and help resolve them quickly."},
{id:1261,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"hard",question:"What is a test burndown chart?",options:["A. A chart showing the number of story points burned per tester","B. A chart tracking remaining test work or open defects over the sprint","C. A chart showing deployment frequency","D. A chart of code coverage over time"],answer:1,explanation:"A test burndown tracks remaining test tasks or open defects over a sprint, showing whether testing will complete on time."},
{id:1262,chapter:"Communicating Test Status in Agile",topic:"Metrics",difficulty:"hard",question:"What is the risk of using test case pass rate as the sole quality metric?",options:["A. It is too difficult to calculate","B. It may hide quality issues if tests lack coverage or are poorly written","C. It measures too many aspects at once","D. It cannot be automated"],answer:1,explanation:"Pass rate alone is misleading — if tests lack coverage or are trivial, a high pass rate does not guarantee good product quality."},
{id:1263,chapter:"Communicating Test Status in Agile",topic:"Agile Quality Metrics",difficulty:"medium",question:"Escaped defects are:",options:["A. Defects found before release","B. Defects found by customers after release","C. Defects removed during code review","D. Defects logged during regression testing"],answer:1,explanation:"Escaped defects are bugs that were not caught during testing and were discovered by end users after release."},
{id:1264,chapter:"Communicating Test Status in Agile",topic:"Agile Quality Metrics",difficulty:"hard",question:"Which metric BEST measures the effectiveness of defect prevention activities?",options:["A. Number of test cases","B. Defect removal efficiency (DRE)","C. Sprint velocity","D. Code coverage"],answer:1,explanation:"DRE = defects found before release / total defects. A high DRE means most defects were caught before reaching production."},
{id:1265,chapter:"Communicating Test Status in Agile",topic:"Sprint Review",difficulty:"easy",question:"What is the purpose of the Sprint Review?",options:["A. To plan the next sprint","B. To demonstrate the increment and gather stakeholder feedback","C. To reflect on the team process","D. To groom the product backlog"],answer:1,explanation:"The Sprint Review demonstrates the product increment to stakeholders and collects feedback to update the backlog."},
{id:1266,chapter:"Communicating Test Status in Agile",topic:"Sprint Review",difficulty:"medium",question:"From a testing perspective, what should a tester contribute at the Sprint Review?",options:["A. Nothing — testers do not attend Sprint Reviews","B. Evidence of testing coverage, results, and any residual risks","C. Only a list of test cases written","D. The number of hours spent testing"],answer:1,explanation:"Testers add value at the Sprint Review by summarising what was tested, coverage achieved, and any quality risks that remain."},
{id:1267,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"medium",question:"Lead time in Kanban is measured as:",options:["A. Time from sprint start to sprint end","B. Time from when work is requested to when it is delivered","C. Time from development start to deployment","D. Time a work item spends in the 'In Progress' column"],answer:1,explanation:"Lead time covers the full journey from request to delivery, including queue time, and is a key customer-facing metric."},
{id:1268,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"hard",question:"Cycle time in Kanban is BEST defined as:",options:["A. The total project duration","B. The time from when work actually starts to when it is done","C. The time between releases","D. The number of items completed per week"],answer:1,explanation:"Cycle time measures active work time — from when a team member starts an item to when it is complete — excluding queue wait."},
{id:1269,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"hard",question:"What is cumulative flow diagram (CFD) used for in Agile?",options:["A. Showing test case execution results","B. Visualising the flow of work items through workflow states over time to spot bottlenecks","C. Tracking individual developer productivity","D. Estimating story points"],answer:1,explanation:"A CFD shows the number of items in each workflow state over time — widening bands indicate bottlenecks or blocked work."},
{id:1270,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"extreme",question:"A team's automated test suite takes 4 hours to run in CI. This is causing delayed feedback. The BEST testing strategy to address this is:",options:["A. Remove the slow tests","B. Restructure tests into a fast unit suite and a slower nightly regression suite, running fast tests on every commit","C. Run tests only before release","D. Hire more testers to run manual tests faster"],answer:1,explanation:"Splitting tests by speed — fast unit tests on every commit, slower tests scheduled — balances feedback speed with coverage."},
{id:1271,chapter:"Communicating Test Status in Agile",topic:"Test Reporting",difficulty:"medium",question:"Which of the following is the LEAST useful content in an Agile sprint test report?",options:["A. Number of stories tested and their status","B. Outstanding risks","C. Detailed biography of each tester","D. Test coverage summary"],answer:2,explanation:"Personal details about testers add no value to a test report — focus should be on results, coverage, and risks."},
{id:1272,chapter:"Communicating Test Status in Agile",topic:"Test Metrics in Agile",difficulty:"hard",question:"A team tracks the number of test cases created per sprint. This metric MOST likely encourages:",options:["A. Better product quality","B. Quantity over quality, incentivising trivial tests to inflate the count","C. More accurate story point estimation","D. Faster deployment"],answer:1,explanation:"Measuring test case quantity creates a perverse incentive to write many low-value tests rather than focussing on risk coverage."},
{id:1273,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"medium",question:"Why should velocity NOT be used to compare different Scrum teams?",options:["A. Because velocity is confidential","B. Because teams size stories differently, making cross-team comparisons meaningless","C. Because velocity only applies to Kanban","D. Because velocity is measured in hours, not points"],answer:1,explanation:"Each team's story point scale is relative and internal — comparing velocities across teams yields no meaningful insight."},
{id:1274,chapter:"Communicating Test Status in Agile",topic:"Retrospective",difficulty:"medium",question:"Which format is commonly used for running sprint retrospectives?",options:["A. Formal written report submitted to management","B. What went well / What didn't go well / Action items","C. Peer review of individual performance","D. Code walkthrough"],answer:1,explanation:"The 'went well / didn't go well / actions' format is a simple, widely-used retrospective structure that drives improvement."},
{id:1275,chapter:"Communicating Test Status in Agile",topic:"Test Dashboard",difficulty:"hard",question:"An Agile team wants to make testing transparency highly visible without meetings. The BEST approach is:",options:["A. Email status reports to stakeholders daily","B. Maintain a physical or digital test status board updated in real time","C. Hold daily test status meetings","D. Publish a weekly PDF report"],answer:1,explanation:"Real-time visible boards (information radiators) provide continuous transparency without requiring additional meetings."},
{id:1276,chapter:"Communicating Test Status in Agile",topic:"Agile Quality Metrics",difficulty:"extreme",question:"A team's defect removal efficiency is 70%. This means:",options:["A. 70% of sprints were defect-free","B. 30% of defects escaped to production","C. 70% of test cases passed","D. 30% of stories were rejected"],answer:1,explanation:"DRE 70% means 30% of defects were not caught before release and escaped to end users — an area for improvement."},
{id:1277,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"medium",question:"In Agile, a tester finds 15 defects in sprint 1 and only 3 in sprint 5. What does this MOST likely indicate?",options:["A. The tester is less thorough in sprint 5","B. Quality is improving as the team stabilises and learns","C. The product is getting more complex","D. The team is skipping testing in sprint 5"],answer:1,explanation:"Decreasing defect counts as sprints progress typically indicate the team is improving quality practices and fixing systemic issues."},
{id:1278,chapter:"Communicating Test Status in Agile",topic:"Test Reporting",difficulty:"hard",question:"Which statement about test reports in Agile is MOST accurate?",options:["A. Formal test reports are mandatory at the end of every sprint","B. Test reporting should be lightweight and integrated into existing Agile ceremonies","C. Test reports are only needed for regulatory projects","D. Only the test lead should produce test reports"],answer:1,explanation:"In Agile, test reporting is typically lightweight and embedded in sprint reviews, retrospectives, and dashboards rather than separate documents."},
{id:1279,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"easy",question:"A tester updates a task card from 'In Testing' to 'Done'. This action primarily:",options:["A. Notifies the Product Owner via email","B. Updates the team's shared view of sprint progress","C. Triggers an automated deployment","D. Locks the story from further change"],answer:1,explanation:"Moving a task card updates the team's shared visual board, maintaining accurate sprint progress for everyone."},
{id:1280,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"medium",question:"A Product Owner asks: 'Is the product ready to release?' The BEST tester response is:",options:["A. 'Yes, all tests passed'","B. 'Here is the test coverage, outstanding risks, and my recommendation based on them'","C. 'That is not my decision'","D. 'We need more time to test'"],answer:1,explanation:"Testers inform release decisions by presenting evidence — coverage, risks, and a quality-based recommendation — not a simple yes/no."},
{id:1281,chapter:"Communicating Test Status in Agile",topic:"Metrics",difficulty:"hard",question:"Mean time to repair (MTTR) is BEST described as:",options:["A. The average time between two failures","B. The average time to fix a defect after it is detected","C. The number of defects fixed per sprint","D. The average test execution time"],answer:1,explanation:"MTTR measures responsiveness to defects — from detection to resolution. Lower MTTR means faster remediation."},
{id:1282,chapter:"Communicating Test Status in Agile",topic:"Agile Quality Metrics",difficulty:"hard",question:"Which of the following BEST indicates a healthy Agile testing process?",options:["A. Zero defects found during testing","B. Defects found and fixed within the same sprint with decreasing escape rate over time","C. A large number of test cases per story","D. All testing completed in the last two days of the sprint"],answer:1,explanation:"Finding and fixing defects within the sprint while reducing escapes over time indicates a maturing, healthy testing process."},
{id:1283,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"medium",question:"What does a flat burndown chart (no reduction in remaining work) mid-sprint indicate?",options:["A. The team is delivering value continuously","B. Work is not being completed — there may be a blocker","C. The sprint is ahead of schedule","D. Estimation was too conservative"],answer:1,explanation:"A flat or rising burn-down mid-sprint signals that work has stalled — likely due to a blocker or scope growth."},
{id:1284,chapter:"Communicating Test Status in Agile",topic:"Retrospective",difficulty:"hard",question:"After several retrospectives with no lasting improvements, the BEST next step is:",options:["A. Stop holding retrospectives","B. Use a different retrospective format and ensure action items have owners and due dates","C. Escalate to management","D. Increase sprint length"],answer:1,explanation:"If retrospectives are ineffective, varying the format and making action items concrete with accountability helps drive real change."},
{id:1285,chapter:"Communicating Test Status in Agile",topic:"Test Reporting",difficulty:"extreme",question:"A regulator requires formal test evidence. In an Agile context, the BEST approach is:",options:["A. Abandon Agile and use a waterfall approach","B. Automate test execution so reports can be generated on demand without slowing the team","C. Produce no test documentation","D. Only document tests after the product is released"],answer:1,explanation:"Automated tests with captured output satisfy regulatory evidence requirements while keeping the Agile team's pace intact."},
// Ch5: Evaluating Exit Criteria and Reporting (1286–1400)
{id:1286,chapter:"Evaluating Exit Criteria and Reporting",topic:"Exit Criteria",difficulty:"easy",question:"Exit criteria in testing are used to:",options:["A. Start a test phase","B. Determine when testing is sufficiently complete to proceed","C. Assign testers to tasks","D. Estimate the number of test cases needed"],answer:1,explanation:"Exit criteria define the conditions that must be met for a test phase or session to be considered complete."},
{id:1287,chapter:"Evaluating Exit Criteria and Reporting",topic:"Exit Criteria",difficulty:"easy",question:"Which of the following is an example of an exit criterion?",options:["A. All developers have reviewed the code","B. All high-priority defects are fixed and no critical defects remain open","C. The sprint planning is complete","D. The product backlog is groomed"],answer:1,explanation:"A common exit criterion is that all critical defects are resolved and high-priority issues are addressed before release."},
{id:1288,chapter:"Evaluating Exit Criteria and Reporting",topic:"Definition of Done",difficulty:"easy",question:"In Agile, the Definition of Done (DoD) is:",options:["A. A list of bugs that must be fixed","B. A shared checklist of criteria a story must meet to be considered complete","C. The sprint goal statement","D. The acceptance criteria for a single user story"],answer:1,explanation:"The DoD is a team-wide shared checklist — code reviewed, tested, documented — that any story must satisfy to be 'done'."},
{id:1289,chapter:"Evaluating Exit Criteria and Reporting",topic:"Definition of Done",difficulty:"medium",question:"Which of the following would MOST likely appear in a team's Definition of Done?",options:["A. Story points estimated","B. Unit tests written and passing, code reviewed, and acceptance criteria met","C. Product Owner has signed a contract","D. Architecture diagrams created"],answer:1,explanation:"A typical DoD includes unit tests passing, code review completed, and acceptance criteria verified — ensuring a releasable increment."},
{id:1290,chapter:"Evaluating Exit Criteria and Reporting",topic:"Exit Criteria",difficulty:"medium",question:"A project team has reached their planned end date but testing is not complete. The BEST action is:",options:["A. Release the product anyway","B. Evaluate residual risks and make a conscious risk-based release decision","C. Delete unfinished test cases","D. Restart testing from scratch"],answer:1,explanation:"When time runs out, teams should assess remaining risks explicitly and make a risk-based decision rather than releasing blindly."},
{id:1291,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Criteria",difficulty:"easy",question:"Acceptance criteria for a user story define:",options:["A. The technical implementation approach","B. The conditions under which the story is accepted as complete by the Product Owner","C. The test automation framework to use","D. The sprint capacity"],answer:1,explanation:"Acceptance criteria set the conditions a story must meet to be accepted — they are the testable boundary of the story."},
{id:1292,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Criteria",difficulty:"medium",question:"Who is PRIMARILY responsible for writing acceptance criteria in Agile?",options:["A. The test lead alone","B. The Product Owner with input from the development team and testers","C. The Scrum Master","D. External auditors"],answer:1,explanation:"The PO owns acceptance criteria but they are best written collaboratively with developers and testers for completeness."},
{id:1293,chapter:"Evaluating Exit Criteria and Reporting",topic:"Definition of Done",difficulty:"medium",question:"What is the relationship between acceptance criteria and the Definition of Done?",options:["A. They are identical","B. Acceptance criteria are story-specific; the DoD applies to every story team-wide","C. The DoD replaces acceptance criteria","D. Acceptance criteria are written after the DoD is met"],answer:1,explanation:"Acceptance criteria are unique per story; DoD is a universal checklist. A story must satisfy both to be truly done."},
{id:1294,chapter:"Evaluating Exit Criteria and Reporting",topic:"Test Completion Report",difficulty:"easy",question:"A test completion report typically includes:",options:["A. Only a list of passed test cases","B. Test summary, coverage achieved, defect statistics, and lessons learned","C. The sprint plan","D. The product roadmap"],answer:1,explanation:"A test completion report summarises what was tested, coverage, defect data, and lessons learned to inform future work."},
{id:1295,chapter:"Evaluating Exit Criteria and Reporting",topic:"Test Completion Report",difficulty:"medium",question:"When is a test completion report produced in Agile?",options:["A. Only at the end of the entire project","B. At the end of a release, sprint, or major test phase","C. Before testing begins","D. During sprint planning"],answer:1,explanation:"In Agile, lightweight test completion reports can be produced at the end of each sprint or release, not just the project end."},
{id:1296,chapter:"Evaluating Exit Criteria and Reporting",topic:"Exit Criteria",difficulty:"hard",question:"Which approach BEST supports evaluating exit criteria in Agile?",options:["A. Using a formal sign-off document signed by the test manager","B. Continuously tracking metrics against defined DoD and release readiness criteria throughout the sprint","C. Checking exit criteria only on the last day of the sprint","D. Delegating exit criteria evaluation to the Scrum Master"],answer:1,explanation:"Continuously monitoring metrics against DoD and readiness criteria prevents last-minute surprises and supports early decisions."},
{id:1297,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Testing",difficulty:"easy",question:"User Acceptance Testing (UAT) verifies that:",options:["A. Unit tests pass","B. The system meets business requirements and is fit for use by end users","C. Code compiles without errors","D. The database schema is correct"],answer:1,explanation:"UAT validates the system from the end-user perspective, confirming it meets business needs and is ready for deployment."},
{id:1298,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Testing",difficulty:"medium",question:"In Agile, acceptance testing is MOST often performed:",options:["A. After all sprints are complete","B. Within the sprint by the team and Product Owner as stories are developed","C. Only by external stakeholders","D. Before development starts"],answer:1,explanation:"Agile teams run acceptance tests continuously within each sprint — the PO verifies stories as they are completed."},
{id:1299,chapter:"Evaluating Exit Criteria and Reporting",topic:"Risk-Based Testing",difficulty:"medium",question:"Risk-based exit criteria would state:",options:["A. All test cases must be executed","B. All high-risk areas must have been tested and risks accepted or mitigated","C. All developers must approve the test results","D. The test plan must be signed off"],answer:1,explanation:"Risk-based exit criteria focus on ensuring that the highest-risk areas are covered — not just that every test case ran."},
{id:1300,chapter:"Evaluating Exit Criteria and Reporting",topic:"Risk-Based Testing",difficulty:"hard",question:"A team has 80% test coverage but the remaining 20% covers the highest-risk functionality. What should they do?",options:["A. Release — 80% is sufficient","B. Prioritise testing the high-risk 20% before making a release decision","C. Delete the uncovered tests","D. Reduce coverage targets"],answer:1,explanation:"Coverage percentage is meaningless without considering risk. The high-risk 20% must be tested before a quality release decision."},
{id:1301,chapter:"Evaluating Exit Criteria and Reporting",topic:"Definition of Done",difficulty:"hard",question:"A team regularly marks stories as 'done' without meeting the full DoD to meet sprint velocity. The MOST likely consequence is:",options:["A. Improved product quality","B. Accumulation of technical debt and hidden quality problems","C. Faster releases with no issues","D. More accurate velocity measurements"],answer:1,explanation:"Bypassing the DoD incurs technical debt — problems are deferred, compounding over time and making future sprints harder."},
{id:1302,chapter:"Evaluating Exit Criteria and Reporting",topic:"Exit Criteria",difficulty:"medium",question:"Entry criteria for a test phase define:",options:["A. What must be done when testing ends","B. The preconditions that must be met before testing can begin","C. The list of defects to fix","D. The test reporting format"],answer:1,explanation:"Entry criteria are preconditions — e.g., test environment ready, test data available — that must be satisfied before testing starts."},
{id:1303,chapter:"Evaluating Exit Criteria and Reporting",topic:"Test Completion Report",difficulty:"hard",question:"A test completion report shows 15 open defects at release. The BEST action is:",options:["A. Delay release until all are fixed","B. Categorise defects by severity and risk, fix critical ones, and document accepted risks for the remainder","C. Close all defects without fixing them","D. Assign all defects to the next sprint backlog and release immediately"],answer:1,explanation:"Risk-based triage of open defects allows informed release — critical ones are fixed, and accepted risks are documented explicitly."},
{id:1304,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Criteria",difficulty:"hard",question:"A user story has vague acceptance criteria. The BEST action before development starts is:",options:["A. Begin development and test later","B. Facilitate a three-amigos session to clarify and detail the acceptance criteria","C. Skip testing for that story","D. Ask the customer to rewrite the story"],answer:1,explanation:"Three amigos (dev, tester, PO) refine vague criteria before development, reducing rework and ensuring shared understanding."},
{id:1305,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Testing",difficulty:"hard",question:"What is the difference between acceptance criteria and acceptance tests?",options:["A. They are the same","B. Acceptance criteria define what must be true; acceptance tests verify those criteria are met","C. Acceptance tests are written first","D. Acceptance criteria are only for non-functional requirements"],answer:1,explanation:"Criteria describe the required condition; tests are the executable steps that verify the condition holds."},
{id:1306,chapter:"Evaluating Exit Criteria and Reporting",topic:"Risk-Based Testing",difficulty:"easy",question:"Product risk in testing refers to:",options:["A. Risk that the project will run over budget","B. Risk that the product will fail to meet its required quality characteristics","C. Risk of developer turnover","D. Risk of scope creep"],answer:1,explanation:"Product risk is the potential that the product has a defect or does not satisfy a quality requirement, harming stakeholders."},
{id:1307,chapter:"Evaluating Exit Criteria and Reporting",topic:"Risk-Based Testing",difficulty:"medium",question:"The risk level of a product risk is MOST commonly calculated as:",options:["A. Impact only","B. Likelihood multiplied by impact","C. The number of defects found","D. Cost of fixing the defect"],answer:1,explanation:"Risk level = likelihood × impact. High likelihood and high impact both elevate risk, driving prioritisation of test effort."},
{id:1308,chapter:"Evaluating Exit Criteria and Reporting",topic:"Exit Criteria",difficulty:"extreme",question:"A CI pipeline fails 30% of the time due to environment issues, not code defects. How should the team treat this when evaluating exit criteria?",options:["A. Always fail the release when the pipeline fails","B. Investigate and fix the unstable environment; do not use flaky pipeline status as a quality gate until stable","C. Ignore all pipeline failures","D. Remove the failing tests from the pipeline"],answer:1,explanation:"Unstable environments make pipeline status unreliable. The root cause must be fixed before the pipeline can be trusted as an exit gate."},
{id:1309,chapter:"Evaluating Exit Criteria and Reporting",topic:"Definition of Done",difficulty:"extreme",question:"A team wants to add performance testing to their DoD but it takes 2 hours per run. The BEST approach is:",options:["A. Remove performance testing from the DoD","B. Run a fast smoke-level performance check in the sprint and schedule full performance tests before each release","C. Only run performance tests in production","D. Add 2 hours to every sprint purely for performance testing"],answer:1,explanation:"Splitting performance testing into a fast in-sprint check and a fuller pre-release run balances DoD rigour with sprint pace."},
{id:1310,chapter:"Evaluating Exit Criteria and Reporting",topic:"Test Completion Report",difficulty:"extreme",question:"A project is cancelled before completion. What should the test completion report include?",options:["A. Nothing — there is nothing to report","B. Work completed, coverage achieved, known defects, and risks that would have been addressed","C. Only the test cases that passed","D. The reason the project was cancelled"],answer:1,explanation:"Even for a cancelled project, a test completion report documents what was done, what remains, and what risks exist — essential knowledge."},
{id:1311,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Testing",difficulty:"extreme",question:"A Product Owner accepts a story despite a known medium-severity defect. This is:",options:["A. Always unacceptable","B. Acceptable if the risk is documented and understood — the PO has authority to accept risk","C. A DoD violation that must be escalated","D. Proof the tester failed"],answer:1,explanation:"The PO has authority to accept known risks. Documenting the accepted defect is essential for transparency and future tracking."},
{id:1312,chapter:"Evaluating Exit Criteria and Reporting",topic:"Risk-Based Testing",difficulty:"extreme",question:"After exit criteria are met and the product is released, a critical defect is found. The MOST useful retrospective finding is:",options:["A. The tester was negligent","B. The risk model did not adequately capture this risk — review and improve risk identification for future sprints","C. Exit criteria should be eliminated","D. Increase test case count by 50%"],answer:1,explanation:"Post-release defects indicate a gap in risk identification. The retrospective should improve the risk model, not just blame individuals."},
{id:1313,chapter:"Evaluating Exit Criteria and Reporting",topic:"Exit Criteria",difficulty:"medium",question:"Which of the following exit criteria is MOST aligned with Agile values?",options:["A. All 500 planned test cases executed","B. All user stories meet their acceptance criteria and the DoD","C. A test plan document signed by the test manager","D. Zero test automation failures"],answer:1,explanation:"Agile exit criteria focus on story completion and DoD satisfaction — outcomes — rather than plan adherence or document sign-off."},
{id:1314,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Criteria",difficulty:"easy",question:"Which format is commonly used to write acceptance criteria in Agile?",options:["A. UML diagrams","B. Given / When / Then (Gherkin)","C. Formal test specifications","D. IEEE 829 test cases"],answer:1,explanation:"Given/When/Then is a widely-used, human-readable format for acceptance criteria that also supports test automation via BDD."},
{id:1315,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Criteria",difficulty:"medium",question:"A story's acceptance criteria state: 'Given a logged-in user, when they submit a form with valid data, then a confirmation email is sent.' What is the 'When' clause?",options:["A. A logged-in user","B. They submit a form with valid data","C. A confirmation email is sent","D. The user logs in"],answer:1,explanation:"'When' describes the action or event being triggered — in this case, submitting the form with valid data."},
{id:1316,chapter:"Evaluating Exit Criteria and Reporting",topic:"Test Completion Report",difficulty:"medium",question:"Which stakeholder is MOST interested in the defect statistics section of a test completion report?",options:["A. The Scrum Master","B. The Product Owner and management, to understand release quality and risk","C. The DevOps engineer","D. The database administrator"],answer:1,explanation:"Defect statistics inform the PO and management about quality and release risk — critical inputs for go/no-go decisions."},
{id:1317,chapter:"Evaluating Exit Criteria and Reporting",topic:"Risk-Based Testing",difficulty:"hard",question:"Residual risk after testing is:",options:["A. Risk that has been fully mitigated","B. Risk that remains after all planned testing is complete","C. Risk identified in the product backlog","D. Risk caused by the testing process itself"],answer:1,explanation:"Residual risk is the remaining risk after mitigation — testers must communicate it clearly so stakeholders can make informed release decisions."},
{id:1318,chapter:"Evaluating Exit Criteria and Reporting",topic:"Definition of Done",difficulty:"hard",question:"Adding non-functional requirements (e.g., performance, security) to the DoD:",options:["A. Slows the team and should be avoided","B. Ensures non-functional quality is built in from the start, not deferred","C. Is only relevant for large enterprise projects","D. Is the sole responsibility of the architect"],answer:1,explanation:"Including NFRs in the DoD means every story is checked for performance and security, preventing a costly end-of-project scramble."},
{id:1319,chapter:"Evaluating Exit Criteria and Reporting",topic:"Exit Criteria",difficulty:"hard",question:"An automated regression suite reports 100% pass rate, but business stakeholders are unhappy with the product. This MOST likely indicates:",options:["A. The stakeholders are wrong","B. The regression suite does not adequately cover business-critical scenarios","C. Automated testing is unreliable","D. Exit criteria based on automated tests are always wrong"],answer:1,explanation:"100% automation pass with unhappy stakeholders points to a coverage gap — the tests verify the wrong or insufficient scenarios."},
{id:1320,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Testing",difficulty:"medium",question:"Alpha testing is performed by:",options:["A. End users in their own environment","B. Internal staff (developers or testers) simulating end-user behaviour","C. Automated test tools","D. External beta testers"],answer:1,explanation:"Alpha testing is conducted internally — by staff who simulate how real users will interact with the product — before external release."},
{id:1321,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Testing",difficulty:"medium",question:"Beta testing is performed by:",options:["A. The development team","B. Real end users in their own environment before final release","C. Automated regression suites","D. The QA team in a controlled lab"],answer:1,explanation:"Beta testing involves real end users operating the product in their own environment to surface real-world issues before general release."},
{id:1322,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Criteria",difficulty:"hard",question:"Non-functional acceptance criteria for a login page might include:",options:["A. The login button must be blue","B. The login page must load within 2 seconds and support 500 concurrent users","C. The developer must review the login form","D. The login form must have 3 fields"],answer:1,explanation:"Non-functional acceptance criteria cover performance, security, and scalability — e.g., load time and concurrency limits."},
{id:1323,chapter:"Evaluating Exit Criteria and Reporting",topic:"Test Completion Report",difficulty:"hard",question:"Lessons learned in a test completion report should:",options:["A. Only describe what went wrong","B. Cover both successes and failures, with actionable recommendations for future testing","C. Be omitted to save time","D. Only be shared internally with the test team"],answer:1,explanation:"Lessons learned should capture both positives and negatives with actionable steps — shared broadly to improve future projects."},
{id:1324,chapter:"Evaluating Exit Criteria and Reporting",topic:"Definition of Done",difficulty:"medium",question:"Who owns the Definition of Done in Scrum?",options:["A. The Scrum Master","B. The entire Scrum team collectively","C. The Product Owner","D. The test lead"],answer:1,explanation:"The DoD is owned collectively by the entire Scrum team — it represents a shared agreement on quality standards."},
{id:1325,chapter:"Evaluating Exit Criteria and Reporting",topic:"Risk-Based Testing",difficulty:"medium",question:"When should risk analysis be performed in Agile?",options:["A. Only before the first sprint","B. Continuously throughout the project, updated as new risks are identified","C. Only during the final sprint","D. Only when the team decides to release"],answer:1,explanation:"Risk analysis in Agile is continuous — new risks emerge as the product evolves, and the team must keep the risk picture current."},
{id:1326,chapter:"Evaluating Exit Criteria and Reporting",topic:"Exit Criteria",difficulty:"easy",question:"What should happen when exit criteria are NOT met at the planned release date?",options:["A. Always postpone the release","B. Assess unmet criteria, evaluate residual risks, and decide with stakeholders whether to release or delay","C. Lower the exit criteria","D. Remove the failing test cases"],answer:1,explanation:"Unmet criteria trigger a risk-based conversation with stakeholders — the decision to release or delay is made explicitly, not arbitrarily."},
{id:1327,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Testing",difficulty:"hard",question:"Contract acceptance testing verifies that:",options:["A. The team met their sprint velocity targets","B. The supplier's deliverable meets the contractually agreed criteria","C. All unit tests pass","D. The Scrum ceremonies were followed"],answer:1,explanation:"Contract acceptance testing checks that externally supplied software meets the agreed contractual specification before acceptance."},
{id:1328,chapter:"Evaluating Exit Criteria and Reporting",topic:"Test Completion Report",difficulty:"easy",question:"A test summary includes: '47 tests run, 44 passed, 3 failed (2 low, 1 medium)'. This information is MOST useful for:",options:["A. Estimating future sprint velocity","B. Making an informed release decision based on test results and risk","C. Planning the next sprint backlog","D. Updating the product roadmap"],answer:1,explanation:"Pass/fail counts with defect severity let stakeholders judge whether the remaining failures pose acceptable release risk."},
{id:1329,chapter:"Evaluating Exit Criteria and Reporting",topic:"Acceptance Criteria",difficulty:"extreme",question:"A story's acceptance criteria are met in testing but the Product Owner rejects it anyway. The MOST productive response is:",options:["A. Escalate to the Scrum Master immediately","B. Facilitate a conversation to understand the gap between the written criteria and the PO's expectation","C. Mark the story as done anyway","D. Blame the PO for poorly written criteria"],answer:1,explanation:"PO rejection with passing criteria indicates a communication gap. A conversation to surface the unstated expectation is the most productive next step."},
{id:1330,chapter:"Evaluating Exit Criteria and Reporting",topic:"Risk-Based Testing",difficulty:"extreme",question:"A security vulnerability is found in production that was present in the codebase for 3 sprints. The MOST useful process improvement is:",options:["A. Fire the tester responsible","B. Add security-focused testing (e.g., SAST, threat modelling) earlier in the sprint and include security in the DoD","C. Increase test case count","D. Hire an external security firm for all future testing"],answer:1,explanation:"Shifting security testing left — SAST in CI, threat modelling in refinement, security in DoD — reduces the window for vulnerabilities to persist."},
// Ch6: Agile Test Planning and Risk Management (1331–1400 start)
{id:1331,chapter:"Agile Test Planning and Risk Management",topic:"Test Planning in Agile",difficulty:"easy",question:"In Agile, test planning is BEST described as:",options:["A. A one-time activity producing a comprehensive test plan document","B. A continuous activity performed at multiple levels — release, sprint, and story","C. Planning done only by the test manager","D. Planning that occurs after all development is complete"],answer:1,explanation:"Agile test planning is continuous and hierarchical — at release level for the big picture and at sprint/story level for details."},
{id:1332,chapter:"Agile Test Planning and Risk Management",topic:"Test Planning in Agile",difficulty:"easy",question:"Which of the following is NOT typically included in an Agile test plan?",options:["A. Test objectives and scope","B. A comprehensive list of every test case with detailed steps","C. Entry and exit criteria","D. Roles and responsibilities"],answer:1,explanation:"Agile test plans are lightweight — exhaustive pre-defined test case lists belong to traditional models, not Agile planning."},
{id:1333,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"easy",question:"Product risk in Agile is BEST managed by:",options:["A. Writing a comprehensive risk register at project start and reviewing it once","B. Continuously identifying, assessing, and mitigating risks throughout each sprint","C. Delegating risk to the Scrum Master","D. Ignoring risks until they materialise"],answer:1,explanation:"Agile risk management is continuous — risks are identified and reassessed every sprint as the product and context evolve."},
{id:1334,chapter:"Agile Test Planning and Risk Management",topic:"Test Levels and Planning",difficulty:"medium",question:"In Agile, release-level test planning is concerned with:",options:["A. The detailed test steps for each user story","B. The overall scope, objectives, and quality strategy for the release","C. Daily standup facilitation","D. Assigning test tasks to developers"],answer:1,explanation:"Release-level planning sets the big picture — what the release aims to achieve, its scope, risks, and the testing strategy across sprints."},
{id:1335,chapter:"Agile Test Planning and Risk Management",topic:"Test Strategy in Agile",difficulty:"medium",question:"A lightweight Agile test strategy document MOST likely includes:",options:["A. All test cases with expected results","B. Scope, approach, tools, environments, and entry/exit criteria","C. Developer task assignments","D. The project business case"],answer:1,explanation:"A lightweight test strategy outlines scope, test approach, tooling, environments, and criteria — enough to guide testing without over-documenting."},
{id:1336,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"medium",question:"Which technique is commonly used to identify product risks in Agile?",options:["A. Waterfall phase-gate reviews","B. Risk brainstorming sessions with the whole team during backlog refinement","C. Formal FMEA documentation","D. Independent risk assessment by an external auditor"],answer:1,explanation:"Risk brainstorming with the whole team during refinement is efficient, collaborative, and Agile-aligned."},
{id:1337,chapter:"Agile Test Planning and Risk Management",topic:"Test Planning in Agile",difficulty:"medium",question:"Regression risk in Agile is BEST managed by:",options:["A. Running full manual regression every sprint","B. Maintaining a fast, comprehensive automated regression suite run on every build","C. Skipping regression testing in early sprints","D. Assigning regression testing to a separate team"],answer:1,explanation:"Automated regression run on every build is the sustainable Agile solution — fast, repeatable, and catches regressions immediately."},
{id:1338,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"hard",question:"Which of the following BEST describes a risk response strategy of 'mitigation'?",options:["A. Ignoring the risk","B. Taking action to reduce the probability or impact of the risk","C. Transferring the risk to a third party","D. Accepting the risk and monitoring it"],answer:1,explanation:"Mitigation reduces either the likelihood or the impact of a risk, or both, through targeted actions."},
{id:1339,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"hard",question:"Risk acceptance in testing means:",options:["A. Fixing all defects before release","B. Consciously deciding to proceed despite the known risk, with the decision documented","C. Ignoring the risk completely","D. Transferring the risk to the customer"],answer:1,explanation:"Risk acceptance is an explicit, documented decision — the team acknowledges the risk exists and chooses to proceed, owning the consequence."},
{id:1340,chapter:"Agile Test Planning and Risk Management",topic:"Test Strategy in Agile",difficulty:"hard",question:"In Agile, who is responsible for the overall test strategy?",options:["A. The test manager working separately","B. The whole team collaboratively, with testers providing testing expertise","C. The Product Owner","D. The Scrum Master"],answer:1,explanation:"In Agile, the whole team owns quality — testers guide test strategy, but it is a collaborative, team-wide responsibility."},
{id:1341,chapter:"Agile Test Planning and Risk Management",topic:"Test Planning in Agile",difficulty:"medium",question:"Sprint-level test planning is PRIMARILY concerned with:",options:["A. Defining the overall release strategy","B. Deciding which stories will be tested, how, and by whom within the sprint","C. Writing the final test completion report","D. Estimating the next quarter's testing budget"],answer:1,explanation:"Sprint-level test planning is tactical — it decides what gets tested this sprint, the approach per story, and who does it."},
{id:1342,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"medium",question:"What is a risk-based test approach?",options:["A. Testing all features equally","B. Prioritising test effort based on identified risks — more testing on high-risk areas","C. Testing only the highest-risk areas","D. Using automated tools for all testing"],answer:1,explanation:"Risk-based testing allocates more effort where the risk of failure is greatest, making testing more effective and efficient."},
{id:1343,chapter:"Agile Test Planning and Risk Management",topic:"Test Strategy in Agile",difficulty:"easy",question:"What is the purpose of a test charter in exploratory testing?",options:["A. To list all regression tests","B. To provide a focused mission for a time-boxed exploratory test session","C. To assign story points to test tasks","D. To define sprint velocity"],answer:1,explanation:"A test charter scopes an exploratory session — it gives the tester a focused mission and boundaries for investigation."},
{id:1344,chapter:"Agile Test Planning and Risk Management",topic:"Test Levels and Planning",difficulty:"hard",question:"In Agile, how should test planning adapt when requirements change mid-sprint?",options:["A. Freeze testing until the next sprint","B. Re-evaluate impacted test coverage and update the test approach for affected stories","C. Reject the requirements change","D. Continue with the original test plan unchanged"],answer:1,explanation:"Agile testers adapt continuously — when requirements change, they reassess which tests are still valid and what new tests are needed."},
{id:1345,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"hard",question:"Technical risk in Agile is BEST addressed by:",options:["A. Avoiding new technologies","B. Including technical risk mitigation (e.g., spikes, proof-of-concept) in sprint planning","C. Delegating all technical decisions to the architect","D. Adding technical risks to the defect backlog"],answer:1,explanation:"Spikes and PoCs within sprints reduce technical uncertainty — discovering and addressing risks early rather than late."},
{id:1346,chapter:"Agile Test Planning and Risk Management",topic:"Test Strategy in Agile",difficulty:"medium",question:"What is a test strategy for scalability?",options:["A. A plan to increase the number of testers","B. A plan to test the system's behaviour under increasing load to verify it meets performance requirements","C. A strategy for testing on multiple browsers","D. A plan for scaling the Scrum team"],answer:1,explanation:"Scalability testing verifies the system handles growing load — users, data, transactions — within acceptable performance limits."},
{id:1347,chapter:"Agile Test Planning and Risk Management",topic:"Test Planning in Agile",difficulty:"easy",question:"What does 'testability' of a user story mean?",options:["A. The story can be implemented quickly","B. The story has clear, measurable acceptance criteria that can be verified by testing","C. The story requires only automated tests","D. The story has been estimated in story points"],answer:1,explanation:"A testable story has unambiguous, verifiable acceptance criteria — if you cannot test it, you cannot confirm it is done."},
{id:1348,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"extreme",question:"A team discovers mid-sprint that a third-party API they depend on is unreliable. The BEST immediate action is:",options:["A. Cancel the sprint","B. Identify the risk, assess the impact, create a stub or mock for testing, and raise the dependency risk in the Daily Scrum","C. Continue as planned and hope the API stabilises","D. Remove all stories that use the API from the sprint"],answer:1,explanation:"Creating a test double addresses the immediate testing need while surfacing the dependency risk for the team to manage transparently."},
{id:1349,chapter:"Agile Test Planning and Risk Management",topic:"Test Strategy in Agile",difficulty:"hard",question:"What is the purpose of a test pyramid strategy?",options:["A. To ensure testers work in a hierarchy","B. To balance test investment — many cheap fast unit tests, fewer integration tests, fewest slow expensive UI tests","C. To prioritise manual over automated testing","D. To define the number of sprints in a release"],answer:1,explanation:"The test pyramid maximises coverage at the unit level (cheap, fast), reduces reliance on slow UI tests, and keeps the suite sustainable."},
{id:1350,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"medium",question:"Which of the following is an example of risk transfer?",options:["A. Adding more tests","B. Taking out cyber insurance for data breach risk","C. Fixing defects","D. Reducing sprint scope"],answer:1,explanation:"Risk transfer shifts the financial or operational consequence of a risk to a third party — insurance is the classic example."},
{id:1351,chapter:"Agile Test Planning and Risk Management",topic:"Test Levels and Planning",difficulty:"medium",question:"Integration testing in Agile MOST commonly focuses on:",options:["A. Testing each class in isolation","B. Verifying interactions between components, services, or systems","C. Testing the full user interface","D. Load testing the database"],answer:1,explanation:"Integration tests verify that components work together correctly — interfaces, contracts, and data flows between modules."},
{id:1352,chapter:"Agile Test Planning and Risk Management",topic:"Test Planning in Agile",difficulty:"hard",question:"How does capacity planning affect sprint-level test planning?",options:["A. It has no effect","B. Available tester capacity constrains how many stories can be tested and how thoroughly in the sprint","C. Only developers' capacity matters","D. Capacity planning is done by the Scrum Master alone"],answer:1,explanation:"Tester capacity directly limits sprint scope — knowing available hours lets the team commit to a realistic, testable sprint backlog."},
{id:1353,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"hard",question:"A newly joined team member lacks experience with the technology stack. This creates which type of risk?",options:["A. Product risk","B. Project risk (resource/knowledge risk)","C. A risk with no impact","D. A compliance risk"],answer:1,explanation:"Knowledge gaps in key roles are project risks — they may slow delivery or introduce defects due to unfamiliarity with the technology."},
{id:1354,chapter:"Agile Test Planning and Risk Management",topic:"Test Strategy in Agile",difficulty:"hard",question:"What is the purpose of a risk-based testing session?",options:["A. To test random areas of the application","B. To focus exploratory testing on the highest-risk areas identified in the risk register","C. To document all found defects","D. To run automated regression tests"],answer:1,explanation:"Risk-based exploratory sessions direct investigative effort to where failures would have the greatest impact."},
{id:1355,chapter:"Agile Test Planning and Risk Management",topic:"Test Planning in Agile",difficulty:"extreme",question:"A team is planning a release with 6 sprints. How should testing be distributed across them?",options:["A. All testing in the last sprint","B. Testing integrated into every sprint with a final regression pass before release","C. Testing only in even-numbered sprints","D. Testing only after all development is complete"],answer:1,explanation:"Testing in every sprint catches defects early and cheap; the final regression pass ensures nothing regressed across the full release."},
{id:1356,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"extreme",question:"A product operates in a regulated industry. How does this affect Agile risk management?",options:["A. Regulation is incompatible with Agile","B. Compliance risks are elevated — the team must include regulatory requirements in the risk register and DoD","C. Regulation only applies to deployment, not testing","D. External auditors handle all compliance risks"],answer:1,explanation:"In regulated industries, compliance is a non-negotiable quality attribute — it must be tracked in risk management and reflected in the DoD."},
{id:1357,chapter:"Agile Test Planning and Risk Management",topic:"Test Levels and Planning",difficulty:"extreme",question:"What is the MAIN challenge of end-to-end testing in a microservices architecture?",options:["A. There are no integration points","B. The number of service interactions creates combinatorial complexity and fragile, slow tests","C. Microservices do not support testing","D. End-to-end tests are not needed in Agile"],answer:1,explanation:"Microservices create many integration points — end-to-end tests become complex, slow, and brittle as the number of services grows."},
{id:1358,chapter:"Agile Test Planning and Risk Management",topic:"Test Strategy in Agile",difficulty:"extreme",question:"A team is transitioning to a DevOps model. How should the test strategy evolve?",options:["A. Remove all manual testing","B. Shift more testing left into the pipeline, automate regression, and use production monitoring as a safety net","C. Increase the number of test phases","D. Delegate all testing to the operations team"],answer:1,explanation:"DevOps demands automated pipelines, shift-left testing, and production monitoring — the test strategy must evolve to embed quality throughout."},
{id:1359,chapter:"Agile Test Planning and Risk Management",topic:"Risk Management in Agile",difficulty:"medium",question:"Which of the following BEST describes a risk heat map?",options:["A. A chart showing temperature during server load tests","B. A visual grid plotting risks by likelihood and impact to prioritise them","C. A sprint burndown chart","D. A map of team locations"],answer:1,explanation:"A heat map visualises risks on a likelihood vs impact grid — red (high both) to green (low both) — making priority clear at a glance."},
{id:1360,chapter:"Agile Test Planning and Risk Management",topic:"Test Planning in Agile",difficulty:"medium",question:"In Agile, who is responsible for making test planning decisions at story level?",options:["A. The test manager in a separate team","B. The tester on the Scrum team, collaborating with the developer and Product Owner","C. The Scrum Master","D. An external QA consultant"],answer:1,explanation:"In Agile, testers within the team own story-level test planning — in close collaboration with developers and the PO."},
];

